aSim_ELM3344      : ARRAY[1..10] OF REAL;  // Simulated Temperature (3 decimals)
bSimTrigger       : BOOL;                  // Simulated Machine Cycle
END_VAR
VAR
fbTimer           : TON;
nState            : INT := 0;
fPhase            : REAL := 0.0;
i                 : INT;
fRandom0to1       : REAL;
fRawValue         : REAL; // Temporary variable for rounding calculation
END_VAR
